class BankAccount:
    def __init__(self, owner, balance=0):
        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount

    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
            return True
        return False

    def is_rich(self):
        return self.balance >= 10000

    def __str__(self):
        status = "Rich!" if self.is_rich() else "Normal"
        return self.owner + " | " + str(self.balance) + " Ks | " + status

a = BankAccount("Nilar", 5000)
print(a)
a.deposit(6000)
print(a)
success = a.withdraw(500)
print("Withdraw worked:", success)
print(a)

